// Sheet columns (0-based after Status col was inserted at B):
// [0]=#  [1]=Status  [2]=Category  [3]=Topic Title
// [4]=Myth  [5]=Twist  [6]=Emotional Hook  [7]=Hook Word
// [8]=Subject  [9]=Environment  [10]=Camera Move  [11]=Lighting Style
// [12]=Energy Vein Location  [13]=Seedance Full Prompt
// [14]=Script Opening Line  [15]=CTA  [16]=Hashtags
// [17]=Est. Virality  [18]=Priority

const res = $input.first().json;
const rows = res.values || [];

const approved = [];
for (let i = 0; i < rows.length; i++) {
  const status = (rows[i][1] || '').toString().trim();
  if (status === 'Approved') {
    approved.push({ idx: i, row: rows[i] });
  }
}

if (approved.length === 0) {
  throw new Error('No Approved topics found. In the Google Sheet, set Status (col B) = Approved for at least one row.');
}

// Pick randomly from approved list
const found = approved[Math.floor(Math.random() * approved.length)];
const sheetRow = found.idx + 2; // data starts at row 2 (row 1 = header)
const r = found.row;

return [{
  json: {
    job_id:               ('SHN-' + Date.now().toString().slice(-8)),
    row_num:              (r[0] || '').toString().trim(),
    status:               (r[1] || '').trim(),
    category:             (r[2] || '').trim(),
    topic:                (r[3] || '').trim(),
    myth:                 (r[4] || '').trim(),
    twist:                (r[5] || '').trim(),
    emotional_hook:       (r[6] || '').trim(),
    hook_word:            (r[7] || '').trim(),
    subject:              (r[8] || '').trim(),
    environment:          (r[9] || '').trim(),
    camera_move:          (r[10] || '').trim(),
    lighting_style:       (r[11] || '').trim(),
    energy_vein_location: (r[12] || '').trim(),
    seedance_ref_prompt:  (r[13] || '').trim(),
    script_opening_line:  (r[14] || '').trim(),
    cta_ref:              (r[15] || '').trim(),
    hashtags_ref:         (r[16] || '').trim(),
    est_virality:         (r[17] || '').trim(),
    priority:             (r[18] || '').trim(),
    sheet_row:            sheetRow,
    source:               'google_sheet'
  }
}];

const raw  = $input.first().json;
const body = (raw.body !== undefined) ? raw.body : raw;

let sheetData = {};
try { sheetData = $('Pick Approved Topic').first().json; } catch(e) {}

const jobId    = body.job_id  || sheetData.job_id  || ('SHN-' + Date.now().toString().slice(-8));
const topic    = body.topic   || sheetData.topic;
const sheetRow = body.sheet_row || sheetData.sheet_row || null;

if (!topic) throw new Error('No topic found. Set Status = Approved in the Google Sheet.');

// 6 clips × 5s = 30s total footage → ~25-30s assembled video (rootxdeep style)
const numClips   = 6;
const clipDurSec = 5;
const wordTarget = 80; // 70-90 words for 25-30 sec narration

return [{ json: {
  ...sheetData,
  job_id: jobId,
  topic,
  sheet_row: sheetRow,
  num_clips: numClips,
  clip_dur_sec: clipDurSec,
  word_target: wordTarget,
  start_time: Date.now()
}}];

const data = $input.first().json;
const {
  topic, category, myth, twist, emotional_hook, hook_word,
  subject, environment, camera_move, lighting_style,
  energy_vein_location, seedance_ref_prompt,
  script_opening_line, cta_ref, hashtags_ref,
  num_clips, word_target
} = data;

const sceneList = Array.from({ length: num_clips }, (_, i) => {
  const part = i < 2 ? 'MYTH HOOK' : i < 5 ? 'TWIST' : i < 7 ? 'EMOTION' : 'CTA';
  return `Scene ${i+1} (${i*5}s - ${(i+1)*5}s) → ${part}`;
}).join('\n  ');

const prompt = `You are a world-class short-form video scriptwriter for the rootxdeep style channel. Your job is to write a complete Myth→Twist→Emotion script AND generate Seedance video prompts for every scene. Use the sheet data as deep reference — do NOT copy it verbatim, use it as inspiration.

--- TOPIC REFERENCE (do not copy verbatim) ---
Topic: ${topic}
Category: ${category}
The Myth (what people think): ${myth}
The Twist (real truth): ${twist}
Emotional Hook: ${emotional_hook}
Hook Word (for yellow text overlay): ${hook_word}
Subject: ${subject}
Environment: ${environment}
Camera Move Reference: ${camera_move}
Lighting Style: ${lighting_style}
Energy Vein Location: ${energy_vein_location}
Seedance Reference Prompt: ${seedance_ref_prompt}
Script Opening Line Reference: ${script_opening_line}
CTA Reference: ${cta_ref}
Hashtags Reference: ${hashtags_ref}

--- THE FORMULA (non-negotiable) ---
MYTH → TWIST → EMOTION
- Scenes 1-2: State the MYTH confidently. What everyone believes. Bold and wrong.
- Scenes 3-4: Drop the TWIST. The complete opposite real truth. Specific, factual, surprising.
- Scene 5: Hit the EMOTION. Awe, shock, dark curiosity, or hope. Connect it to something bigger.
- Scene 6: CTA — save this / follow for more / comment what surprised you.

--- NARRATION RULES ---
1. Total: ${word_target} words (80-120 range). SHORT punchy sentences.
2. Tone: calm, direct, slightly amazed — like a smart friend at dinner, NOT a documentary.
3. NEVER use "I", "we", "you", "our", "your" — pure factual third-person voice.
4. Every sentence either states the myth OR reveals the twist OR lands the emotion. Zero filler.
5. The opening sentence must state the myth in a way that hooks INSTANTLY.

--- SEEDANCE PROMPT RULES for each scene ---
Every seedance_prompt MUST follow this EXACT structure:

"Cinematic photorealistic 4K video, 9:16 vertical, 5 seconds. [SUBJECT] [ACTION] in [ENVIRONMENT]. Glowing golden-orange energy veins pulse and crack through [energy_vein_location] from inside — like liquid lightning flowing through its nervous system — branching and flickering subtly beneath the surface. Cold [teal/steel blue/misty green/grey] atmosphere contrasts with the warm inner orange glow of the energy veins. [CAMERA MOVE]. Volumetric god rays. Atmospheric fog or haze. Shallow depth of field. Film grain texture. ARRI ALEXA cinematic color grade. Epic nature documentary tone. No motion blur."

CAMERA MOVES to choose from:
- "Slow dolly push-in toward chest" → for emotion/survival scenes
- "Low-angle upward hero shot" → for power/strength scenes
- "Extreme close-up racking into the eyes" → for intelligence/revelation scenes
- "Wide establishing crane shot pulling back" → for context/scale scenes
- "Orbital slow rotation" → for science/structure scenes

CATEGORY → SCENE TYPE:
- Animal/Nature → animal in dramatic natural environment (misty forest, ocean, tundra)
- Human/History → person performing relevant action in dramatic setting
- Science/Biology → lab or microscopic environment, clinical cold blue
- Technology/Space → industrial, cosmic, or governmental setting
- Comparison → two subjects glowing with identical energy veins, face to face

SCENE STRUCTURE (EXACTLY ${num_clips} scenes, 5 seconds each):
  ${sceneList}

--- REQUIRED OUTPUT FORMAT ---
Return ONLY raw JSON — no markdown, no explanation, no code block:
{
  "narration": "full script as one continuous spoken text",
  "opening_line": "the exact opening hook sentence (Scene 1 narration)",
  "cta": "the call to action final line",
  "scenes": [
    {
      "scene_number": 1,
      "start_sec": 0,
      "end_sec": 5,
      "formula_part": "MYTH",
      "narration_segment": "exact words spoken during this scene",
      "seedance_prompt": "complete Seedance prompt following the exact structure above",
      "negative_prompt": "cartoon, anime, CGI animation, text, letters, numbers, labels, watermarks, blur, low quality, flat lighting, motion blur"
    }
  ],
  "title": "punchy scroll-stopping title under 60 chars",
  "hashtags": "#tag1 #tag2 #tag3 #tag4 #tag5 #tag6 #tag7 #tag8",
  "highlight_keywords": ["KeyWord1", "KeyWord2", "KeyWord3"]
}`;

return [{ json: {
  ...data,
  gemini_script_request: {
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: {
      maxOutputTokens: 8192,
      temperature: 0.70,
      responseMimeType: 'application/json'
    }
  }
}}];

const response  = $input.first().json;
const jobConfig = $('Set Job Config').first().json;
const expectedClips = jobConfig.num_clips || 8;

if (!response.candidates || !response.candidates[0] || !response.candidates[0].content) {
  throw new Error('Gemini response empty or blocked: ' + JSON.stringify(response).slice(0, 300));
}

let rawText = response.candidates[0].content.parts[0].text.trim();
rawText = rawText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch(e) {
  const s = rawText.indexOf('{');
  const end = rawText.lastIndexOf('}');
  if (s !== -1 && end !== -1) {
    parsed = JSON.parse(rawText.slice(s, end + 1));
  } else {
    throw new Error('Failed to parse Gemini JSON: ' + rawText.slice(0, 200));
  }
}

if (!parsed.scenes || !Array.isArray(parsed.scenes)) {
  throw new Error('Gemini returned no scenes array');
}

// Enforce exactly expectedClips scenes
if (parsed.scenes.length < expectedClips) {
  while (parsed.scenes.length < expectedClips) {
    const i = parsed.scenes.length;
    const last = parsed.scenes[parsed.scenes.length - 1];
    parsed.scenes.push({
      ...last,
      scene_number: i + 1,
      start_sec: i * 5,
      end_sec: (i + 1) * 5,
      formula_part: 'EMOTION'
    });
  }
} else if (parsed.scenes.length > expectedClips) {
  parsed.scenes = parsed.scenes.slice(0, expectedClips);
}

console.log('Scenes: ' + parsed.scenes.length + ' | Topic: ' + jobConfig.topic);

const seedance_prompts  = parsed.scenes.map(s => s.seedance_prompt);
const negative_prompts  = parsed.scenes.map(s => s.negative_prompt || 'cartoon, anime, CGI animation, text, letters, numbers, labels, watermarks, blur, low quality, flat lighting, motion blur');

return [{ json: {
  ...jobConfig,
  narration:          parsed.narration,
  opening_line:       parsed.opening_line || parsed.scenes[0]?.narration_segment || '',
  cta:                parsed.cta || jobConfig.cta_ref || '',
  scenes:             parsed.scenes,
  seedance_prompts,
  negative_prompts,
  title:              parsed.title    || jobConfig.topic,
  hashtags:           parsed.hashtags || jobConfig.hashtags_ref || '#nature #didyouknow #mindblown',
  highlight_keywords: parsed.highlight_keywords || []
}}];
